```
#include <pybind11/pybind11.h>

struct Number {
    Number() : number(5) {}
    int number;
};

namespace py = pybind11;

PYBIND11_PLUGIN(example) {
    py::module m("example", "pybind11 example plugin");

    py::class_<Number>(m, "Number")
    .def(py::init<>())
    .def(py::init<const Number&>())
    .def_readwrite("number",    &Number::number);

    return m.ptr();
}
